// 📊 GENERADOR DE INFORME DIARIO DE COBRANZAS - Plan Óvalo
// Versión corregida: soporta tipos 2, 3 y 5 + fix clasificación success/error

const datos = $input.all().map(item => item.json);
const fechaHoy = new Date().toLocaleDateString();
const horaReporte = new Date().toLocaleTimeString();
const diaExtraido = Number($('extrae_dia1').item.json.dia_extraido);
const esCanalEmail = [7, 14, 21].includes(diaExtraido);
const canalLabel = esCanalEmail ? 'Correo Electrónico' : 'WhatsApp';
const canalEmoji = esCanalEmail ? '📧' : '💬';

// ===== FILTRADO DE REGISTROS DEL DÍA =====
const registrosHoy = datos.filter(item => {
  const fechaRegistro = item.fecha_aviso;
  return fechaRegistro === fechaHoy;
});

console.log(`Total registros en tabla: ${datos.length}`);
console.log(`Registros del día (${fechaHoy}): ${registrosHoy.length}`);

// Si no hay registros del día, crear un informe vacío
if (registrosHoy.length === 0) {
  return [{
    json: {
      subject: `📊 Informe Diario Cobranzas - ${fechaHoy} | Sin registros`,
      htmlEmail: `
        <html>
        <body style="font-family: Arial, sans-serif; padding: 20px;">
          <h2>📊 Informe Diario de Cobranzas</h2>
          <p><strong>Fecha:</strong> ${fechaHoy} | <strong>Hora:</strong> ${horaReporte}</p>
          <div style="background: #fff3cd; padding: 15px; border-left: 4px solid #ffc107; margin: 20px 0;">
            <p><strong>⚠️ No hay registros para el día de hoy</strong></p>
            <p>No se procesaron avisos en la fecha actual.</p>
          </div>
        </body>
        </html>
      `,
      resumenEjecutivo: {
        totalProcesados: 0,
        exitosos: 0,
        fallidos: 0,
        tasaExito: '0'
      },
      fechaReporte: fechaHoy,
      horaReporte: horaReporte
    }
  }];
}

// ===== FUNCIÓN AUXILIAR: Normalizar estado_aviso =====
function esExitoso(estadoAviso) {
  // Normalizar a minúsculas y comparar
  const estado = String(estadoAviso || '').toLowerCase().trim();
  return estado === 'success';
}

function esFallido(estadoAviso) {
  const estado = String(estadoAviso || '').toLowerCase().trim();
  return estado.includes('error') || estado === '' || estado === 'undefined';
}

// ===== CÁLCULO DE MÉTRICAS =====
const totalRegistros = registrosHoy.length;
const exitosos = registrosHoy.filter(item => esExitoso(item.estado_aviso)).length;
const fallidos = registrosHoy.filter(item => esFallido(item.estado_aviso)).length;
const tasaExito = totalRegistros > 0 ? ((exitosos / totalRegistros) * 100).toFixed(2) : '0';

// ===== ANÁLISIS POR TIPO DE ESTADO (AHORA CON TIPO 2, 3 Y 5) =====
const tipo2 = registrosHoy.filter(item => 
  String(item.estado) === '2' || parseInt(item.estado) === 2
).length;

const tipo3 = registrosHoy.filter(item => 
  String(item.estado) === '3' || parseInt(item.estado) === 3
).length;

const tipo5 = registrosHoy.filter(item => 
  String(item.estado) === '5' || parseInt(item.estado) === 5
).length;

// ===== FUNCIÓN: Obtener descripción del tipo =====
function obtenerTipoEstado(estado) {
  const est = parseInt(estado);
  switch(est) {
    case 2: return 'Ahorrista Libre de Deuda (Tipo 2)';
    case 3: return 'Ahorrista Moroso (Tipo 3)';
    case 5: return 'Adjudicado en Mora (Tipo 5)';
    default: return `Tipo ${estado}`;
  }
}

// ===== CLIENTES EXITOSOS =====
const clientesExitosos = registrosHoy
  .filter(item => esExitoso(item.estado_aviso))
  .map(item => ({
    nombre: item.nombre || 'N/A',
    grupo: item.grupo || 'N/A',
    orden: item.orden || 'N/A',
    cuotasImpagas: item.cuotas_impagas || '0',
    montoDeuda: item.monto_deuda_total || '0',
    estado: obtenerTipoEstado(item.estado),
    tipoNumerico: parseInt(item.estado),
    ciudad: item.ciudad || 'N/A',
    provincia: item.provincia || 'N/A',
    telefono: item.telefono || 'N/A',
    horaEnvio: item.hora_aviso || 'N/A'
  }));

// ===== CLIENTES CON PROBLEMAS =====
const clientesConProblemas = registrosHoy
  .filter(item => esFallido(item.estado_aviso))
  .map(item => ({
    nombre: item.nombre || 'N/A',
    grupo: item.grupo || 'N/A',
    orden: item.orden || 'N/A',
    motivoError: item.estado_aviso || 'Error desconocido',
    estado: obtenerTipoEstado(item.estado),
    tipoNumerico: parseInt(item.estado),
    ciudad: item.ciudad || 'N/A',
    provincia: item.provincia || 'N/A',
    telefono: item.telefono || 'N/A',
    horaIntento: item.hora_aviso || 'N/A'
  }));

// ===== CÁLCULO DE MONTO TOTAL =====
const montoTotalDeuda = registrosHoy
  .filter(item => esExitoso(item.estado_aviso))
  .reduce((sum, item) => {
    const montoStr = String(item.monto_deuda_total || '0').replace(',', '.');
    const monto = parseFloat(montoStr);
    return sum + (isNaN(monto) ? 0 : monto);
  }, 0);

// ===== DISTRIBUCIÓN POR PROVINCIA =====
const provincias = {};
registrosHoy.forEach(item => {
  const prov = item.provincia || 'Sin Provincia';
  if (!provincias[prov]) {
    provincias[prov] = { total: 0, exitosos: 0, fallidos: 0 };
  }
  provincias[prov].total++;
  if (esExitoso(item.estado_aviso)) {
    provincias[prov].exitosos++;
  } else {
    provincias[prov].fallidos++;
  }
});

// ===== GENERAR SUBJECT DEL EMAIL =====
//const subject = `📊 Informe Diario Cobranzas Plan Óvalo - ${fechaHoy} | ${exitosos}/${totalRegistros} exitosos (${tasaExito}%)`;
const subject = `📊 Informe Diario Cobranzas Plan Óvalo [${canalEmoji} ${canalLabel}] - ${fechaHoy} | ${exitosos}/${totalRegistros} exitosos (${tasaExito}%)`;
// ===== GENERAR HTML DEL EMAIL =====
const htmlEmail = `
<!DOCTYPE html>
