// Los móviles en redes Claro/Personal/Movistar no tienen patrones fijos
// pero podemos descartar números que claramente son fijos (ej: empiezan con 0)
function isMobileAR(tenDigits) {
  if (!tenDigits || tenDigits.length !== 10) return false;
  // Descartar si empieza con 0 (nunca debería llegar acá, pero por las dudas)
  if (tenDigits.startsWith('0')) return false;
  // Número válido de 10 dígitos sin prefijo → aceptar como móvil
  // (Si necesitás validación más estricta por área, se puede extender acá)
