function cleanNumber(val) {
  if (!val && val !== 0) return null;
  const digits = String(val).replace(/\D/g, '').trim();
  return digits.length > 0 ? digits : null;
}

// Normaliza a formato WhatsApp Argentina: 54XXXXXXXXXX (sin el 9 intermedio)
function formatWhatsAppAR(digits) {
  if (!digits) return null;

  // Sacar prefijo 549 (13 dígitos) → quedamos con 10
  if (digits.length === 13 && digits.startsWith('549')) {
    digits = digits.substring(3);
  }
  // Sacar prefijo 54 (12 dígitos) → quedamos con 10
  else if (digits.length === 12 && digits.startsWith('54')) {
    digits = digits.substring(2);
  }
  // Sacar 9 inicial (11 dígitos) → quedamos con 10
  else if (digits.length === 11 && digits.startsWith('9')) {
    digits = digits.substring(1);
  }

  // Debe quedar en 10 dígitos
  if (digits.length !== 10) return null;

  return '54' + digits;
}

// Heurística para distinguir celular vs fijo en Argentina
// Celulares: área de 2 dígitos (11) → 8 dígitos de abonado
//            área de 3 dígitos     → 7 dígitos de abonado
//            área de 4 dígitos     → 6 dígitos de abonado
// Los móviles en redes Claro/Personal/Movistar no tienen patrones fijos
// pero podemos descartar números que claramente son fijos (ej: empiezan con 0)
function isMobileAR(tenDigits) {
  if (!tenDigits || tenDigits.length !== 10) return false;
  // Descartar si empieza con 0 (nunca debería llegar acá, pero por las dudas)
  if (tenDigits.startsWith('0')) return false;
  // Número válido de 10 dígitos sin prefijo → aceptar como móvil
  // (Si necesitás validación más estricta por área, se puede extender acá)
  return true;
}

function formatDate(dateStr) {
  if (!dateStr) return '';
  const [y, m, d] = dateStr.split('-');
  return `${d}/${m}/${y}`;
}

function formatAmount(amount) {
  return Number(amount).toLocaleString('es-AR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

